def generate_jwt_token(username, mfa_verified=False):
    """Generate a JWT token for the user."""
    payload = {
        'username': username,
        'mfa_verified': mfa_verified,
        'exp': datetime.utcnow() + timedelta(hours=app.config['JWT_EXPIRATION_HOURS']),
        'iat': datetime.utcnow()
    }
    return jwt.encode(payload, app.config['JWT_SECRET'], algorithm='HS256')


def verify_jwt_token(token):
    """Verify and decode a JWT token."""
    try:
        payload = jwt.decode(token, app.config['JWT_SECRET'], algorithms=['HS256'])
        return payload
    except jwt.ExpiredSignatureError:
        return None
    except jwt.InvalidTokenError:
        return None


def login_required(f):
    """Decorator to require login for web routes."""
    @wraps(f)
    def decorated_function(*args, **kwargs):
        if 'username' not in session or not session.get('authenticated'):
            return redirect(url_for('login'))
        return f(*args, **kwargs)
    return decorated_function


def api_auth_required(f):
    """Decorator to require authentication for API routes (JWT or API key)."""
    @wraps(f)
    def decorated_function(*args, **kwargs):
        # Check for JWT Bearer token
        auth_header = request.headers.get('Authorization', '')
        if auth_header.startswith('Bearer '):
            token = auth_header[7:]
            payload = verify_jwt_token(token)
            if payload:
                request.current_user = payload['username']
                return f(*args, **kwargs)

        # Check for API key
        api_key = request.headers.get('X-API-Key', '')
        if api_key and api_key in api_keys_db:
            request.current_user = api_keys_db[api_key]
            return f(*args, **kwargs)

        return jsonify({'error': 'Authentication required', 'message': 'Provide a valid Bearer token or X-API-Key header'}), 401
    return decorated_function


def generate_qr_code(provisioning_uri):
    """Generate a QR code image as base64 string."""
    qr = qrcode.QRCode(version=1, box_size=10, border=5)
    qr.add_data(provisioning_uri)
    qr.make(fit=True)
    img = qr.make_image(fill_color="black", back_color="white")
    buffer = io.BytesIO()
    img.save(buffer, format='PNG')
    buffer.seek(0)
    return base64.b64encode(buffer.getvalue()).decode()


